## 3. Redis 설정 파일

### application.yml (환경별 분리)

```yaml
# application-local.yml
spring:
  data:
    redis:
      host: localhost
      port: 6379
      password: ""
      timeout: 2000ms
      lettuce:
        pool:
          max-active: 8
          max-idle: 8
          min-idle: 2
          max-wait: -1ms

  cache:
    type: redis
    redis:
      time-to-live: 300000  # 기본 5분 (ms)
      cache-null-values: false

# application-stg.yml / application-prod.yml
spring:
  data:
    redis:
      host: ${REDIS_HOST}
      port: ${REDIS_PORT}
      password: ${REDIS_PASSWORD}
      ssl:
        enabled: true  # prod 환경은 TLS 활성화
```

---

## 4. Redis 캐시 설정 클래스

위치: `domain/src/main/kotlin/com/maum/backend/config/CacheConfig.kt`

```kotlin
@Configuration
@EnableCaching
class CacheConfig(
    private val redisConnectionFactory: RedisConnectionFactory,
) {

    /**
     * 캐시 이름별 TTL 정의
     * 도메인 특성에 따라 차별화된 TTL 적용
     */
    companion object {
        const val CACHE_USER_PROFILE    = "userProfile"      // 사용자 프로필: 10분
        const val CACHE_USER_SETTINGS   = "userSettings"     // 사용자 설정: 30분
        const val CACHE_PRODUCT_LIST    = "productList"      // 상품 목록: 5분
        const val CACHE_NOTIFICATION    = "notification"     // 알림 설정: 15분
        const val CACHE_FOLLOW_COUNT    = "followCount"      // 팔로우 수: 3분
        const val CACHE_FEED_LIST       = "feedList"         // 피드 목록: 2분
        const val CACHE_CALL_HISTORY    = "callHistory"      // 통화 이력: 5분
    }

    @Bean
    fun cacheManager(): RedisCacheManager {
        val defaultConfig = RedisCacheConfiguration.defaultCacheConfig()
            .serializeKeysWith(
                RedisSerializationContext.SerializationPair.fromSerializer(StringRedisSerializer())
            )
            .serializeValuesWith(
                RedisSerializationContext.SerializationPair.fromSerializer(genericJackson2JsonRedisSerializer())
            )
            .disableCachingNullValues()
            .entryTtl(Duration.ofMinutes(5))  // 기본 TTL

        val cacheConfigurations = mapOf(
            CACHE_USER_PROFILE  to defaultConfig.entryTtl(Duration.ofMinutes(10)),
            CACHE_USER_SETTINGS to defaultConfig.entryTtl(Duration.ofMinutes(30)),
            CACHE_PRODUCT_LIST  to defaultConfig.entryTtl(Duration.ofMinutes(5)),
            CACHE_NOTIFICATION  to defaultConfig.entryTtl(Duration.ofMinutes(15)),
            CACHE_FOLLOW_COUNT  to defaultConfig.entryTtl(Duration.ofMinutes(3)),
            CACHE_FEED_LIST     to defaultConfig.entryTtl(Duration.ofMinutes(2)),
            CACHE_CALL_HISTORY  to defaultConfig.entryTtl(Duration.ofMinutes(5)),
        )

        return RedisCacheManager.builder(redisConnectionFactory)
            .cacheDefaults(defaultConfig)
            .withInitialCacheConfigurations(cacheConfigurations)
            .build()
    }

    @Bean
    fun genericJackson2JsonRedisSerializer(): GenericJackson2JsonRedisSerializer {
        val mapper = ObjectMapper().apply {
            registerModule(KotlinModule.Builder().build())
            registerModule(JavaTimeModule())
            // LocalDateTime 등 Java Time 타입 직렬화 설정
            disable(SerializationFeature.WRITE_DATES_AS_TIMESTAMPS)
            // 타입 정보 포함 (역직렬화 시 정확한 타입 복원)
            activateDefaultTyping(
                LaissezFaireSubTypeValidator.instance,
                ObjectMapper.DefaultTyping.NON_FINAL,
                JsonTypeInfo.As.PROPERTY
            )
        }
        return GenericJackson2JsonRedisSerializer(mapper)
    }

    @Bean
    fun redisTemplate(redisConnectionFactory: RedisConnectionFactory): RedisTemplate<String, Any> {
        return RedisTemplate<String, Any>().apply {
            connectionFactory = redisConnectionFactory
            keySerializer = StringRedisSerializer()
            valueSerializer = genericJackson2JsonRedisSerializer()
            hashKeySerializer = StringRedisSerializer()
            hashValueSerializer = genericJackson2JsonRedisSerializer()
        }
    }
}
```

---

## 5. 캐시 적용 대상 후보 분석

아래는 Maum 앱의 도메인 특성상 캐시 효과가 높은 순위로 정리한 것입니다.

| 우선순위 | 서비스 | 메서드 | 이유 | 예상 개선 |
|---------|--------|--------|------|-----------|
| 1 | UserService | getUserProfile | 모든 API 공통 호출, 변경 빈도 낮음 | DB 쿼리 90% 감소 |
| 2 | ProductService | getProductList | 앱 홈 진입 시 항상 조회, 거의 변경 없음 | 응답시간 200ms -> 10ms |
| 3 | NotificationService | getNotificationSettings | 사용자별 설정값, 읽기 전용에 가까움 | DB 쿼리 85% 감소 |
| 4 | FollowService | getFollowCount | 피드/프로필 진입마다 호출 | 응답시간 150ms -> 5ms |
| 5 | FeedService | getFeedList | 홈 피드, 반복 조회 빈도 높음 | 응답시간 500ms -> 50ms |
| 6 | CallService | getCallHistory | 통화 이력 반복 조회 | DB 부하 70% 감소 |

---

## 6. Before / After 실제 코드 예시

### 6-1. UserProfile 캐시 적용

**Before (캐시 없음):**

```kotlin
// user/src/main/kotlin/com/maum/backend/service/UserService.kt
@Service
class UserService(
    private val userRepository: UserRepository,
    private val profileRepository: ProfileRepository,
) {
    // 매 요청마다 JOIN 쿼리 2회 실행
    fun getUserProfile(userId: String): UserProfileResponse {
        val user = userRepository.findById(userId)
            .orElseThrow { NotFoundException("사용자 없음: $userId") }
        val profile = profileRepository.findByUserId(userId)
            ?: throw NotFoundException("프로필 없음: $userId")

        return UserProfileResponse(
            id = user.id,
            nickname = profile.nickname,
            profileImageUrl = profile.profileImageUrl,
            bio = profile.bio,
            createdAt = user.createdAt,
        )
    }
}
```

**After (@Cacheable 적용):**

```kotlin
// user/src/main/kotlin/com/maum/backend/service/UserService.kt
@Service
class UserService(
    private val userRepository: UserRepository,
    private val profileRepository: ProfileRepository,
) {
    /**
     * 사용자 프로필 조회 - Redis 캐시 적용
     * Key 전략: "userProfile::userId:{userId}"
     * TTL: 10분 (CacheConfig에서 정의)
     * 캐시 히트 시 DB 쿼리 0회
     */
    @Cacheable(
        cacheNames = [CacheConfig.CACHE_USER_PROFILE],
        key = "'userId:' + #userId",
    )
    fun getUserProfile(userId: String): UserProfileResponse {
        val user = userRepository.findById(userId)
            .orElseThrow { NotFoundException("사용자 없음: $userId") }
        val profile = profileRepository.findByUserId(userId)
            ?: throw NotFoundException("프로필 없음: $userId")

        return UserProfileResponse(
            id = user.id,
            nickname = profile.nickname,
            profileImageUrl = profile.profileImageUrl,
            bio = profile.bio,
            createdAt = user.createdAt,
        )
    }

    /**
     * 프로필 수정 시 캐시 무효화
     * 프로필 수정 완료 후 해당 userId 캐시 제거
     */
    @CacheEvict(
        cacheNames = [CacheConfig.CACHE_USER_PROFILE],
        key = "'userId:' + #userId",
    )
    fun updateProfile(userId: String, request: UpdateProfileRequest): UserProfileResponse {
        val profile = profileRepository.findByUserId(userId)
            ?: throw NotFoundException("프로필 없음: $userId")

        // 엔티티 업데이트 로직...
        return getUserProfile(userId)
    }

    /**
     * 회원 탈퇴 시 관련 캐시 전체 제거
     */
    @Caching(evict = [
        CacheEvict(cacheNames = [CacheConfig.CACHE_USER_PROFILE], key = "'userId:' + #userId"),
        CacheEvict(cacheNames = [CacheConfig.CACHE_USER_SETTINGS], key = "'userId:' + #userId"),
        CacheEvict(cacheNames = [CacheConfig.CACHE_FOLLOW_COUNT], key = "'userId:' + #userId"),
    ])
    fun withdrawUser(userId: String) {
        // 탈퇴 처리...
    }
}
```

---

### 6-2. ProductList 캐시 적용 (공통 데이터)

**Before:**

```kotlin
@Service
class ProductService(
    private val productRepository: ProductRepository,
