```

**After:**

```kotlin
@Service
class ProductService(
    private val productRepository: ProductRepository,
) {
    /**
     * 활성 상품 목록 - 전체 공용 캐시
     * Key 전략: "productList::active" (단일 키, 사용자 구분 없음)
     * TTL: 5분
     * 상품 등록/수정/삭제 시 CacheEvict
     */
    @Cacheable(
        cacheNames = [CacheConfig.CACHE_PRODUCT_LIST],
        key = "'active'",
    )
    fun getActiveProducts(): List<ProductResponse> {
        return productRepository.findByStatusOrderBySortOrderAsc(status = 1)
            .map { ProductResponse.from(it) }
