    /**
     * 상품 상태 변경 시 목록 캐시 전체 제거
     */
    @CacheEvict(
        cacheNames = [CacheConfig.CACHE_PRODUCT_LIST],
        allEntries = true,  // 상품 목록 전체 무효화
    )
    fun updateProductStatus(productId: String, status: Int) {
