### 6-3. FollowCount 캐시 (고빈도 조회)

**Before:**

```kotlin
@Service
class FollowService(
    private val followRepository: FollowRepository,
) {
    // 피드/프로필 진입 시마다 COUNT 쿼리 실행 - 부하 큰 집계 쿼리
    fun getFollowCount(userId: String): FollowCountResponse {
        val followerCount = followRepository.countByTargetUserId(userId)
        val followingCount = followRepository.countByUserId(userId)
        return FollowCountResponse(followerCount, followingCount)
    }
}
```

**After:**

```kotlin
@Service
class FollowService(
    private val followRepository: FollowRepository,
) {
    /**
     * 팔로우 수 캐시 - 집계 쿼리 부하 제거
     * Key 전략: "followCount::userId:{userId}"
     * TTL: 3분 (실시간성 vs 성능 트레이드오프)
     * 팔로우/언팔로우 이벤트 시 CacheEvict
     */
    @Cacheable(
        cacheNames = [CacheConfig.CACHE_FOLLOW_COUNT],
        key = "'userId:' + #userId",
    )
    fun getFollowCount(userId: String): FollowCountResponse {
        val followerCount = followRepository.countByTargetUserId(userId)
        val followingCount = followRepository.countByUserId(userId)
        return FollowCountResponse(followerCount, followingCount)
    }

    @CacheEvict(
        cacheNames = [CacheConfig.CACHE_FOLLOW_COUNT],
        key = "'userId:' + #followerId",  // 팔로워의 following 수 변경
    )
    fun follow(followerId: String, targetUserId: String) {
        // 팔로우 처리...
        // targetUserId 캐시도 무효화 필요 (별도 이벤트 발행 또는 @Caching 사용)
        evictFollowCount(targetUserId)
    }

    @CacheEvict(
        cacheNames = [CacheConfig.CACHE_FOLLOW_COUNT],
        key = "'userId:' + #userId",
    )
    fun evictFollowCount(userId: String) { /* 무효화용 메서드 */ }
}
```

