## 6. Before / After 실제 코드 예시

### 6-1. UserProfile 캐시 적용

**Before (캐시 없음):**

```kotlin
// user/src/main/kotlin/com/maum/backend/service/UserService.kt
@Service
class UserService(
    private val userRepository: UserRepository,
    private val profileRepository: ProfileRepository,
) {
    // 매 요청마다 JOIN 쿼리 2회 실행
    fun getUserProfile(userId: String): UserProfileResponse {
        val user = userRepository.findById(userId)
            .orElseThrow { NotFoundException("사용자 없음: $userId") }
        val profile = profileRepository.findByUserId(userId)
            ?: throw NotFoundException("프로필 없음: $userId")

        return UserProfileResponse(
            id = user.id,
            nickname = profile.nickname,
            profileImageUrl = profile.profileImageUrl,
            bio = profile.bio,
            createdAt = user.createdAt,
        )
    }
}
```

**After (@Cacheable 적용):**

```kotlin
// user/src/main/kotlin/com/maum/backend/service/UserService.kt
@Service
class UserService(
    private val userRepository: UserRepository,
    private val profileRepository: ProfileRepository,
) {
    /**
     * 사용자 프로필 조회 - Redis 캐시 적용
     * Key 전략: "userProfile::userId:{userId}"
     * TTL: 10분 (CacheConfig에서 정의)
     * 캐시 히트 시 DB 쿼리 0회
     */
    @Cacheable(
        cacheNames = [CacheConfig.CACHE_USER_PROFILE],
        key = "'userId:' + #userId",
    )
    fun getUserProfile(userId: String): UserProfileResponse {
        val user = userRepository.findById(userId)
            .orElseThrow { NotFoundException("사용자 없음: $userId") }
        val profile = profileRepository.findByUserId(userId)
            ?: throw NotFoundException("프로필 없음: $userId")

        return UserProfileResponse(
            id = user.id,
            nickname = profile.nickname,
            profileImageUrl = profile.profileImageUrl,
            bio = profile.bio,
            createdAt = user.createdAt,
        )
    }

    /**
     * 프로필 수정 시 캐시 무효화
     * 프로필 수정 완료 후 해당 userId 캐시 제거
     */
    @CacheEvict(
        cacheNames = [CacheConfig.CACHE_USER_PROFILE],
        key = "'userId:' + #userId",
    )
    fun updateProfile(userId: String, request: UpdateProfileRequest): UserProfileResponse {
        val profile = profileRepository.findByUserId(userId)
            ?: throw NotFoundException("프로필 없음: $userId")

        // 엔티티 업데이트 로직...
        return getUserProfile(userId)
    }

    /**
     * 회원 탈퇴 시 관련 캐시 전체 제거
     */
    @Caching(evict = [
        CacheEvict(cacheNames = [CacheConfig.CACHE_USER_PROFILE], key = "'userId:' + #userId"),
        CacheEvict(cacheNames = [CacheConfig.CACHE_USER_SETTINGS], key = "'userId:' + #userId"),
        CacheEvict(cacheNames = [CacheConfig.CACHE_FOLLOW_COUNT], key = "'userId:' + #userId"),
    ])
    fun withdrawUser(userId: String) {
        // 탈퇴 처리...
    }
}
```

