### 6-4. CachePut을 활용한 갱신 후 즉시 캐시 업데이트

```kotlin
@Service
class UserSettingsService(
    private val settingsRepository: UserSettingsRepository,
) {
    @Cacheable(
        cacheNames = [CacheConfig.CACHE_USER_SETTINGS],
        key = "'userId:' + #userId",
    )
    fun getUserSettings(userId: String): UserSettingsResponse {
        return settingsRepository.findByUserId(userId)
            ?.let { UserSettingsResponse.from(it) }
            ?: UserSettingsResponse.default()
    }

    /**
     * @CachePut: 메서드를 항상 실행하고 결과를 캐시에 즉시 반영
     * @CacheEvict와 달리 다음 요청 전에 캐시가 갱신됨
     */
    @CachePut(
        cacheNames = [CacheConfig.CACHE_USER_SETTINGS],
        key = "'userId:' + #userId",
    )
    fun updateUserSettings(userId: String, request: UpdateSettingsRequest): UserSettingsResponse {
        val settings = settingsRepository.findByUserId(userId)
            ?: UserSettingsEntity(userId = userId)

        // 설정 업데이트...
        val saved = settingsRepository.save(settings)
        return UserSettingsResponse.from(saved)
    }
}
```

